<template><div class="center-page"><header><h1>提现审核</h1><p>核对支付宝掩码与金额，转账后再标记已支付。</p></header><el-table :data="rows" v-loading="loading"><el-table-column prop="organization_id" label="组织"/><el-table-column label="金额"><template #default="s">¥{{(s.row.amount_cents/100).toFixed(2)}}</template></el-table-column><el-table-column prop="payout_account_mask" label="支付宝"/><el-table-column prop="status" label="状态"/><el-table-column label="操作" width="240"><template #default="s"><el-button v-if="s.row.status==='pending'" link type="success" @click="decide(s.row.id,'approved')">批准</el-button><el-button v-if="s.row.status==='pending'" link type="danger" @click="decide(s.row.id,'rejected')">驳回</el-button><el-button v-if="s.row.status==='approved'" link type="primary" @click="decide(s.row.id,'paid')">标记已转账</el-button></template></el-table-column></el-table></div></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{supabase}from'@/lib/supabase';import{pluginCenterApi}from'@/api/pluginCenter';const rows=ref<any[]>([]),loading=ref(false);const load=async()=>{loading.value=true;const{data,error}=await supabase.from('plugin_center_withdrawals').select('*').order('requested_at',{ascending:false});if(error)ElMessage.error(error.message);rows.value=data??[];loading.value=false;};const decide=async(id:string,decision:string)=>{let reason='';if(decision==='rejected')reason=await ElMessageBox.prompt('请输入驳回原因','提现审核').then(x=>x.value);await pluginCenterApi.decideWithdrawal(id,decision,reason);ElMessage.success('状态已更新');await load();};onMounted(load);</script><style scoped>.center-page{padding:4px}header{margin-bottom:22px}header p{color:var(--el-text-color-secondary)}</style>